import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  // Simplest: empty input
  it.todo("returns [] for an empty input (no living cells)");

  // Single cell — underpopulation (0 neighbors)
  it.todo("single cell [(0,0)] dies from underpopulation -> []");

  // Rule 1: Underpopulation with two adjacent cells (each has 1 neighbor)
  it.todo("Rule 1 underpopulation: [(0,1), (1,1)] both die (each has 1 neighbor) -> []");

  // Rule 4: Reproduction — dead cell with exactly 3 live neighbors becomes alive
  // From spec: ##. / #.. / ... — cells [(0,0), (1,0), (0,1)]; dead (1,1) has 3 neighbors -> alive
  it.todo("Rule 4 reproduction: dead cell (1,1) with exactly 3 live neighbors becomes alive");

  // Rule 2: Survival — live cell with 2 or 3 neighbors lives on
  // From spec: ### / ... / .#. — center (1,1) has 3 live neighbors and survives
  it.todo("Rule 2 survival: center cell (1,1) with 3 live neighbors survives to next generation");

  // Rule 3: Overpopulation — live cell with > 3 neighbors dies
  // From spec: ### / .#. / ### — center (1,1) has 4 neighbors -> dies
  it.todo("Rule 3 overpopulation: center cell (1,1) with 4 live neighbors dies");

  // Block (still life) — every live cell has exactly 3 neighbors, no dead cell gains 3
  it.todo("Block still life [(0,0), (1,0), (0,1), (1,1)] remains unchanged");

  // Blinker (oscillator) — vertical to horizontal, introduces negative coordinates
  it.todo("Blinker oscillator: vertical [(0,0), (0,1), (0,2)] becomes horizontal [(-1,1), (0,1), (1,1)]");

  // Negative coordinates handling (infinite grid)
  it.todo("handles negative coordinates: blinker starting at negative x/y oscillates correctly");
});

